/**
 * Pure validation functions for order operations.
 *
 * All functions are side-effect-free. They accept pre-fetched data
 * (e.g. a looked-up user) and throw on invalid input.
 */

import type { CreateOrderInput, OrderStatus } from '../models/order.js';
import type { User } from '../models/user.js';

const STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
  pending: ['confirmed', 'cancelled'],
  confirmed: ['shipped', 'cancelled'],
  shipped: ['delivered'],
  delivered: [],
  cancelled: [],
};

/**
 * Check whether a status transition is allowed.
 */
export function isValidStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): boolean {
  return STATUS_TRANSITIONS[from].includes(to);
}

/**
 * Validate a status transition, throwing on invalid.
 */
export function validateStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): void {
  if (!isValidStatusTransition(from, to)) {
    throw new Error(`Invalid status transition: ${from} -> ${to}`);
  }
}

/**
 * Validate that the user for an order exists.
 */
export function validateOrderUserExists(
  user: User | undefined,
  userId: string,
): asserts user is User {
  if (!user) {
    throw new Error(`User not found: ${userId}`);
  }
}

/**
 * Validate a create-order input (items must not be empty).
 */
export function validateCreateOrderInput(input: CreateOrderInput): void {
  if (input.items.length === 0) {
    throw new Error('Order must have at least one item');
  }
}

/**
 * Pure validation functions for user operations.
 *
 * All functions are side-effect-free. They accept pre-fetched data
 * (e.g. a looked-up user) and throw on invalid input.
 */

import type { User } from '../models/user.js';

/**
 * Validate that a user exists.
 */
export function validateUserExists(
  user: User | undefined,
  id: string,
): asserts user is User {
  if (!user) {
    throw new Error(`User not found: ${id}`);
  }
}

/**
 * Validate that an email is not already taken (for user creation).
 */
export function validateEmailUnique(
  existingUser: User | undefined,
  email: string,
): void {
  if (existingUser) {
    throw new Error(`User with email ${email} already exists`);
  }
}

/**
 * Validate that an email is not already in use by another user (for updates).
 */
export function validateEmailNotInUse(
  existingUser: User | undefined,
  email: string,
): void {
  if (existingUser) {
    throw new Error(`Email ${email} is already in use`);
  }
}

